<?php
 class BookController extends PageController { private PDO $db; public function __construct() { parent::__construct(); $this->db = Database::getInstance(); } public function action_list(): void { try { $stmt = $this->db->query('SELECT * FROM books ORDER BY id DESC'); $books = $stmt->fetchAll(); } catch (PDOException $e) { $books = []; } $this->render('book/list', [ 'books' => $books, ], 'Технічна бібліотека'); } public function action_create(): void { if (!isset($_SESSION['user_id'])) { $this->redirect('auth/login'); return; } $errors = []; $old = []; if ($this->request->isPost()) { $old = $this->request->allPost(); $errors = $this->validate($old); if (empty($errors)) { try { $stmt = $this->db->prepare( 'INSERT INTO books (title, author, genre, price, pages)
                         VALUES (:title, :author, :genre, :price, :pages)' ); $stmt->execute([ ':title' => trim($old['title']), ':author' => trim($old['author']), ':genre' => trim($old['genre'] ?? ''), ':price' => (float)($old['price'] ?? 0), ':pages' => (int)($old['pages'] ?? 0), ]); $_SESSION['flash_success'] = 'Запис "' . trim($old['title']) . '" додано до бібліотеки!'; } catch (PDOException $e) { $_SESSION['flash_success'] = 'Помилка БД: ' . $e->getMessage(); } $this->redirect('book/list'); return; } } $this->render('book/create', [ 'errors' => $errors, 'old' => $old, ], 'Додати документ'); } public function action_edit(): void { if (!isset($_SESSION['user_id'])) { $this->redirect('auth/login'); return; } $id = (int)$this->request->get('id', 0); if ($id <= 0) { $this->redirect('book/list'); return; } try { $stmt = $this->db->prepare('SELECT * FROM books WHERE id = :id'); $stmt->execute([':id' => $id]); $book = $stmt->fetch(); } catch (PDOException $e) { $book = null; } if (!$book) { $this->redirect('book/list'); return; } $errors = []; if ($this->request->isPost()) { $data = $this->request->allPost(); $errors = $this->validate($data); if (empty($errors)) { try { $stmt = $this->db->prepare( 'UPDATE books SET title = :title, author = :author, genre = :genre,
                         price = :price, pages = :pages WHERE id = :id' ); $stmt->execute([ ':title' => trim($data['title']), ':author' => trim($data['author']), ':genre' => trim($data['genre'] ?? ''), ':price' => (float)($data['price'] ?? 0), ':pages' => (int)($data['pages'] ?? 0), ':id' => $id, ]); $_SESSION['flash_success'] = 'Запис оновлено!'; } catch (PDOException $e) { $_SESSION['flash_success'] = 'Помилка БД: ' . $e->getMessage(); } $this->redirect('book/list'); return; } $book = array_merge($book, $data); } $this->render('book/edit', [ 'book' => $book, 'errors' => $errors, ], 'Редагувати документ'); } public function action_delete(): void { if (!isset($_SESSION['user_id'])) { $this->redirect('auth/login'); return; } if ($this->request->isPost()) { $id = (int)$this->request->post('id', 0); if ($id > 0) { try { $stmt = $this->db->prepare('DELETE FROM books WHERE id = :id'); $stmt->execute([':id' => $id]); $_SESSION['flash_success'] = 'Запис видалено з бібліотеки!'; } catch (PDOException $e) { $_SESSION['flash_success'] = 'Помилка видалення.'; } } } $this->redirect('book/list'); } private function validate(array $data): array { $errors = []; if (trim($data['title'] ?? '') === '') { $errors['title'] = 'Назва документа є обов\'язковою.'; } if (trim($data['author'] ?? '') === '') { $errors['author'] = 'Автор є обов\'язковим.'; } $price = $data['price'] ?? ''; if ($price !== '' && (!is_numeric($price) || (float)$price < 0)) { $errors['price'] = 'Ціна має бути невід\'ємним числом.'; } $pages = $data['pages'] ?? ''; if ($pages !== '' && (!is_numeric($pages) || (int)$pages < 1)) { $errors['pages'] = 'Кількість сторінок має бути не менше 1.'; } return $errors; } } 